SELECT *
  FROM sys12_calendar
 WHERE sys12_company_id = #{companyId}
   AND TO_CHAR(sys12_day, 'yyyy') = #{year}
   AND (#{month} = '%' OR TO_CHAR(sys12_day, 'MM') = #{month})
 ORDER BY sys12_day

